import { useState } from "react";
import galleryData from "../data/GaleriaFotos.jsx";
import FlechaAbajo from "../icons/flecha-abajo.svg";

const MasonryGrid = () => {

  const COLUMNAS = 3;
  const FILA_INICIAL = 1;
  const FILAS_POR_CLICK = 2;

  const IMAGENES_INICIALES = COLUMNAS * FILA_INICIAL;
  const IMAGENES_POR_CLICK = COLUMNAS * FILAS_POR_CLICK;

  const [cantidadVisible, setCantidadVisible] = useState(IMAGENES_INICIALES);

  const imagenesMostrar = galleryData.slice(0, cantidadVisible);

  const estaExpandido = cantidadVisible >= galleryData.length;

  const toggleMostrar = () => {

    if (estaExpandido) {
      // PLEGAR
      setCantidadVisible(IMAGENES_INICIALES);
    } else {
      // EXPANDIR
      setCantidadVisible(prev =>
        Math.min(prev + IMAGENES_POR_CLICK, galleryData.length)
      );
    }

  };

  return (
    <div className="flex flex-col items-center">

      {/* GRID */}
      <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
        {imagenesMostrar.map((img) => (
          <img
            key={img.id}
            src={img.src}
            alt={img.alt}
            className="w-full h-auto rounded-xl shadow-md hover:scale-[1.02] transition"
          />
        ))}
      </div>

      {/* BOTON SIEMPRE VISIBLE */}
      {galleryData.length > IMAGENES_INICIALES && (
        <button
          onClick={toggleMostrar}
          className="mt-6 hover:scale-110 transition"
        >
          <img
            src={FlechaAbajo}
            className={`w-10 opacity-80 transition-transform duration-300 ${estaExpandido ? "rotate-180" : ""
              }`}
          />
        </button>
      )}

    </div>
  );
};

export default MasonryGrid;
